// app/pages/comparison.js
import React, {useState, useEffect} from 'react';
import {useParams} from 'remix';
import PackraftCard from '../components/PackraftCard';

const ComparisonPage = () => {
  const {id} = useParams();
  const [packrafts, setPackrafts] = useState([]);
  const [comparison, setComparison] = useState({});

  useEffect(() => {
    fetch(`/api/shopify/products/${id}`)
      .then(response => response.json())
      .then(data => setPackrafts(data));
  }, [id]);

  const handleComparison = (packraftId) => {
    setComparison(packrafts.find(packraft => packraft.id === packraftId));
  };

  return (
    <div>
      <h1>Comparaison de packrafts</h1>
      <ul>
        {packrafts.map(packraft => (
          <li key={packraft.id}>
            <PackraftCard packraft={packraft} />
            <button onClick={() => handleComparison(packraft.id)}>Comparer</button>
          </li>
        ))}
      </ul>
      {comparison && (
        <div>
          <h2>Comparaison de {comparison.name}</h2>
          <p>{comparison.description}</p>
        </div>
      )}
    </div>
  );
};

export default ComparisonPage;
</CODE>

